import type { ChatMessage } from '@ax/core';

// ---------------------------------------------------------------------------
// Inbox entry + claim result
//
// These are the shapes the long-poll inbox stores and returns. `InboxEntry` is
// what producers queue; `ClaimResult` is what the long-poll claim resolves to.
//
// Cursor semantics (matches @ax/ipc-protocol SessionNextMessageResponseSchema):
//   - `user-message` / `cancel`: returned `cursor` is the NEXT cursor the
//     caller should request (delivered-index + 1).
//   - `timeout`: returned `cursor` echoes the input cursor (no advancement).
// ---------------------------------------------------------------------------

export type InboxEntry =
  | { type: 'user-message'; payload: ChatMessage }
  | { type: 'cancel' };

export type ClaimResult =
  | { type: 'user-message'; payload: ChatMessage; cursor: number }
  | { type: 'cancel'; cursor: number }
  | { type: 'timeout'; cursor: number };

// ---------------------------------------------------------------------------
// Service hook I/O shapes
//
// Kept as plain interfaces ŌĆö no Zod here. The IPC server validates wire
// payloads separately; in-process hook calls rely on TypeScript at compile
// time plus a small runtime shape-check inside the hook handlers.
// ---------------------------------------------------------------------------

export interface SessionCreateInput {
  sessionId: string;
  workspaceRoot: string;
}

export interface SessionCreateOutput {
  sessionId: string;
  token: string;
}

export interface SessionResolveTokenInput {
  token: string;
}

export type SessionResolveTokenOutput =
  | { sessionId: string; workspaceRoot: string }
  | null;

export interface SessionQueueWorkInput {
  sessionId: string;
  entry: InboxEntry;
}

export interface SessionQueueWorkOutput {
  cursor: number;
}

export interface SessionClaimWorkInput {
  sessionId: string;
  cursor: number;
  timeoutMs: number;
}

export type SessionClaimWorkOutput = ClaimResult;

export interface SessionTerminateInput {
  sessionId: string;
}

// Empty-object return ŌĆö idempotent terminate. `Record<string, never>` (rather
// than bare `{}`) is the TS idiom for "no properties allowed"; the bus's return
// shape stays explicit so a future widening is an intentional type change.
export type SessionTerminateOutput = Record<string, never>;
---STORAGE_SCHEMA---
import { Kysely, SqliteDialect, type Generated } from 'kysely';
import BetterSqlite3 from 'better-sqlite3';

export interface KvRow {
  key: string;
  value: Buffer;
  updated_at: Generated<string>;
}

export interface Database {
  kv: KvRow;
}

export function openDatabase(databasePath: string): Kysely<Database> {
  const driver = new BetterSqlite3(databasePath);
  driver.pragma('journal_mode = WAL');
  driver.exec(`
    CREATE TABLE IF NOT EXISTS kv (
      key TEXT PRIMARY KEY,
      value BLOB NOT NULL,
      updated_at TEXT NOT NULL DEFAULT (datetime('now'))
    )
  `);
  return new Kysely<Database>({
    dialect: new SqliteDialect({ database: driver }),
  });
}
---SESSION_STORE---
import { randomBytes } from 'node:crypto';
import { PluginError } from '@ax/core';

const PLUGIN_NAME = '@ax/session-inmemory';

// Plugin-specific error codes. Core's `PluginErrorCode` union is open
// (`| (string & {})`), so these flow through without casts.
export const DUPLICATE_SESSION = 'duplicate-session';
export const UNKNOWN_SESSION = 'unknown-session';

// ---------------------------------------------------------------------------
// Session store
//
// Two maps:
//   - `sessionId ŌåÆ SessionRecord` (primary)
//   - `token ŌåÆ sessionId`        (reverse lookup for O(1) resolve)
//
// `terminate()` sets a flag on the record but does NOT delete. The reverse
// map still contains the terminated token, but `resolveToken()` checks the
// flag and returns null ŌĆö keeps the record around for forensic tooling and
// lets the future postgres impl match the same semantics with a tombstone.
//
// Token minting: 32 bytes of crypto.randomBytes, base64url-encoded, no
// padding ŌĆö 43 chars exactly, matches /^[A-Za-z0-9_-]{43}$/. Never JWT (I9).
// ---------------------------------------------------------------------------

export interface SessionRecord {
  readonly sessionId: string;
  readonly workspaceRoot: string;
  readonly token: string;
  terminated: boolean;
}

export interface SessionStore {
  create(sessionId: string, workspaceRoot: string): SessionRecord;
  resolveToken(token: string): { sessionId: string; workspaceRoot: string } | null;
  get(sessionId: string): SessionRecord | null;
  terminate(sessionId: string): void;
}

function mintToken(): string {
  return randomBytes(32).toString('base64url');
}

export function createSessionStore(): SessionStore {
  const bySessionId = new Map<string, SessionRecord>();
  const byToken = new Map<string, string>();

  return {
    create(sessionId, workspaceRoot) {
      if (bySessionId.has(sessionId)) {
        throw new PluginError({
          code: DUPLICATE_SESSION,
          plugin: PLUGIN_NAME,
          hookName: 'session:create',
          message: `session '${sessionId}' already exists`,
        });
      }
      const token = mintToken();
      const record: SessionRecord = {
        sessionId,
        workspaceRoot,
        token,
        terminated: false,
      };
      bySessionId.set(sessionId, record);
      byToken.set(token, sessionId);
      return record;
    },

    resolveToken(token) {
      const sessionId = byToken.get(token);
      if (sessionId === undefined) return null;
      const record = bySessionId.get(sessionId);
      if (record === undefined || record.terminated) return null;
      return {
        sessionId: record.sessionId,
        workspaceRoot: record.workspaceRoot,
      };
    },

    get(sessionId) {
      return bySessionId.get(sessionId) ?? null;
    },

    terminate(sessionId) {
      const record = bySessionId.get(sessionId);
      if (record === undefined) return; // idempotent no-op
      record.terminated = true;
    },
  };
}

