/**
 * k8s sandbox provider ŌĆö Kubernetes pod-based isolation.
 *
 * Always cold-starts a new pod. Communication is via HTTP:
 *   - Host delivers work payload via HTTP POST to the pod
 *   - Agent sends IPC requests via HTTP to /internal/ipc
 *   - Agent sends response via agent_response IPC action
 *
 * No k8s Exec or Attach API ŌĆö eliminates stdin/stdout complexity and
 * log pollution issues.
 *
 * Environment:
 *   K8S_NAMESPACE ŌĆö target namespace (default: "ax")
 *   K8S_POD_IMAGE ŌĆö container image (default: "ax/agent:latest")
 *   K8S_RUNTIME_CLASS ŌĆö runtime class name (default: "gvisor")
 *   K8S_IMAGE_PULL_SECRETS ŌĆö comma-separated secret names for private registries
 */

import { PassThrough } from 'node:stream';
import { randomUUID } from 'node:crypto';
import type { SandboxProvider, SandboxConfig, SandboxProcess } from './types.js';
import type { Config } from '../../types.js';
import { getLogger } from '../../logger.js';
import { canonicalEnv } from './canonical-paths.js';

const logger = getLogger().child({ component: 'sandbox-k8s' });

const DEFAULT_IMAGE = 'ax/agent:latest';
const DEFAULT_NAMESPACE = 'ax';
const DEFAULT_RUNTIME_CLASS = 'gvisor';
const DEFAULT_CPUS = 1;
const DEFAULT_MEMORY_LIMIT = '1Gi';

/** Synthetic PID counter ŌĆö k8s pods don't have local PIDs. */
let nextPid = 100_000;

/**
 * Detect "pod already gone" 404s from the @kubernetes/client-node delete API.
 *
 * The client surfaces 404 in two shapes depending on version/path:
 *   - `err.code === 404` (numeric)
 *   - `err.body` is the serialized k8s Status JSON: `{"reason":"NotFound","code":404,...}`
 *     or contains the literal phrase "not found".
 *
 * We accept either. Anything else is a real cleanup failure worth a warn.
 */
function isPodGoneError(err: any): boolean {
  if (err?.code === 404) return true;
  if (err?.statusCode === 404) return true;
  if (err?.response?.statusCode === 404) return true;
  const body = typeof err?.body === 'string' ? err.body : '';
  if (body && /not found/i.test(body)) return true;
  return false;
}

/**
 * Build a k8s pod manifest for a sandbox instance (cold-start path).
 */
