    const wire = toWireChanges([
      { path: 'x', kind: 'put', content: new Uint8Array([1, 2, 3, 4]) },
    ]);
    const parsed = FileChangeSchema.parse(wire[0]);
    if (parsed.kind === 'put') {
      expect(Array.from(parsed.content)).toEqual([1, 2, 3, 4]);
    } else {
      throw new Error('expected put');
    }
  });
});

