    const resp = (await deps.client.call('workspace.commit-notify', {
      parentVersion,
      commitRef: commitRefGen(),
      message: 'turn',
      changes: toWireChanges(snapshot),
    })) as WorkspaceCommitNotifyResponse;
    if (resp.accepted) {
      // Host received it; safe to drain.
